async function main() {
  console.log(`Processing ${updates.length} product updates for batch 17...`);
  let successCount = 0;
  let errorCount = 0;

  for (const update of updates) {
    try {
      const product = await prisma.product.findUnique({
        where: { slug: update.slug }
      });

      if (!product) {
        console.log(`  WARNING: Product not found: ${update.slug}`);
        errorCount++;
        continue;
      }

      await prisma.product.update({
        where: { slug: update.slug },
        data: {
          description: update.description,
          metaDescription: update.metaDescription,
        }
      });

      const wordCount = update.description.split(/\s+/).length;
      const metaLen = update.metaDescription.length;
      console.log(`  OK: ${update.slug} (words: ${wordCount}, meta: ${metaLen} chars)`);
      successCount++;
    } catch (err) {
      console.log(`  ERROR: ${update.slug}: ${err.message}`);
      errorCount++;
    }
  }

  console.log(`\nDone! Success: ${successCount}, Errors: ${errorCount}`);
  await prisma.$disconnect();
}

main();
